import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
const Chat = () => {
  const [darkMode, setDarkMode] = useState(false); // State for dark mode
  return (
    <div className="h-screen flex overflow-hidden">
      <div className={`w-[30%] flex flex-col h-full overflow-scroll scrollbar-hide ${darkMode ? "bg-[#0a0f27] text-white" : "bg-[#dde3f6]"}`}>
        <div className={`h-[65px] flex justify-center items-center sticky top-0 shadow-md ${darkMode ? "bg-[#0a0f27] bg-opacity-90 text-white" : "bg-[#dde3f6]"}`}></div>
      </div>
        <div className={`w-[70%] h-full overflow-scroll scrollbar-hide ${darkMode ? "bg-[#0a0f27] bg-opacity-90 text-white" : "bg-white"}`}>
           <div className={`h-[65px] flex justify-center items-center sticky top-0 shadow-md w-full ${darkMode ? "bg-[#0a0f27] bg-opacity-90 text-white" : ""}`}></div>
        </div>
    </div>
  );
};

export default Chat;
